/**
 * @packageDocumentation
 * Synchronize or validate the presets matrix from canonical rule metadata.
 */
// @ts-check

import { readFile, writeFile } from "node:fs/promises";
import { resolve } from "node:path";

// @ts-ignore -- Generated by the build; this script intentionally validates built output.
import builtPlugin from "../dist/plugin.js";

const matrixSectionHeading = "## Rule matrix";
const presetIndexPath = resolve("docs", "rules", "presets", "index.md");

/** @param {string} markdown */
const detectLineEnding = (markdown) =>
    markdown.includes("\r\n") ? "\r\n" : "\n";

/** @param {string} markdown */
const getMatrixSectionBounds = (markdown) => {
    const startOffset = markdown.indexOf(matrixSectionHeading);

    if (startOffset < 0) {
        throw new Error(
            "docs/rules/presets/index.md is missing the '## Rule matrix' section heading."
        );
    }

    const nextHeadingOffset = markdown.indexOf(
        "\n## ",
        startOffset + matrixSectionHeading.length
    );

    return {
        endOffset: nextHeadingOffset < 0 ? markdown.length : nextHeadingOffset,
        startOffset,
    };
};

/** @param {string} markdown */
export const extractPresetsMatrixSection = (markdown) => {
    const { endOffset, startOffset } = getMatrixSectionBounds(markdown);

    return markdown.slice(startOffset, endOffset);
};

const preferredRuleOrder = [
    "stylelint",
    "disallow-stylelint-formatter",
    "disallow-stylelint-ignore-disables",
    "prefer-stylelint-define-config",
    "prefer-stylelint-report-descriptionless-disables",
    "prefer-stylelint-report-invalid-scope-disables",
    "prefer-stylelint-report-needless-disables",
    "prefer-stylelint-report-unscoped-disables",
];
const rules = Object.entries(builtPlugin.rules).toSorted(([left], [right]) => {
    const leftIndex = preferredRuleOrder.indexOf(left);
    const rightIndex = preferredRuleOrder.indexOf(right);

    if (leftIndex >= 0 && rightIndex >= 0) {
        return leftIndex - rightIndex;
    }

    if (leftIndex >= 0) {
        return -1;
    }

    if (rightIndex >= 0) {
        return 1;
    }

    return left.localeCompare(right);
});

/**
 * @param {string} presetName
 * @param {string} ruleName
 */
const isRuleEnabledInPreset = (presetName, ruleName) => {
    const preset = builtPlugin.configs[presetName];
    const presetEntries = Array.isArray(preset) ? preset : [preset];

    return presetEntries.some(
        (entry) =>
            entry !== undefined &&
            (entry.rules?.[`stylelint-2/${ruleName}`] === "error" ||
                entry.rules?.[`stylelint-2/${ruleName}`] === "warn")
    );
};

export const generatePresetsRulesMatrixSectionFromRules = () => {
    const tableRows = rules.map(([ruleName, ruleModule]) => {
        const fix = ruleModule.meta?.fixable === "code" ? "🔧" : "—";
        const presetIcons = [
            isRuleEnabledInPreset("recommended", ruleName) ? "🟡" : null,
            isRuleEnabledInPreset("stylesheets", ruleName) ? "🎨" : null,
            isRuleEnabledInPreset("configs", ruleName) ? "🛠️" : null,
            isRuleEnabledInPreset("all", ruleName) ? "🟣" : null,
        ]
            .filter((value) => value !== null)
            .join(" ");
        const docsUrl = ruleModule.meta?.docs?.url;

        if (typeof docsUrl !== "string") {
            throw new TypeError(`Rule '${ruleName}' is missing meta.docs.url.`);
        }

        return `| [\`${ruleName}\`](${docsUrl}) | ${fix} | ${presetIcons} |`;
    });

    return [
        "## Rule matrix",
        "",
        "- `Fix` legend:",
        "  - `🔧` = autofixable",
        "  - `—` = report only",
        "- `Preset key` legend:",
        "  - `🟡` — `stylelint2.configs.recommended`",
        "  - `🎨` — `stylelint2.configs.stylesheets`",
        "  - `🛠️` — `stylelint2.configs.configs`",
        "  - `🟣` — `stylelint2.configs.all`",
        "",
        "| Rule | Fix | Preset key |",
        "| --- | :-: | :-- |",
        ...tableRows,
        "",
    ].join("\n");
};

export const syncPresetsRulesMatrix = async ({ writeChanges = false } = {}) => {
    const markdown = await readFile(presetIndexPath, "utf8");
    const lineEnding = detectLineEnding(markdown);
    const expectedSection = generatePresetsRulesMatrixSectionFromRules()
        .replace(/\n/gv, lineEnding)
        .trimEnd();
    const { endOffset, startOffset } = getMatrixSectionBounds(markdown);
    const currentSection = markdown.slice(startOffset, endOffset).trimEnd();

    if (currentSection === expectedSection) {
        return { changed: false };
    }

    if (!writeChanges) {
        throw new Error("Presets matrix is out of sync with plugin metadata.");
    }

    const updatedMarkdown = `${markdown.slice(0, startOffset)}${expectedSection}${markdown.slice(endOffset)}`;
    await writeFile(presetIndexPath, updatedMarkdown, "utf8");

    return { changed: true };
};

const currentEntryPath = process.argv[1];

if (
    typeof currentEntryPath === "string" &&
    import.meta.url === new URL(currentEntryPath, "file:").href
) {
    await syncPresetsRulesMatrix({
        writeChanges: process.argv.includes("--write"),
    });
}
